Patching the snake motion to animate between grid squares.
_____javascript
const w = space.chat.transient || {};
const src = w['snake-game'] || w.snakeGame || w.snake || w.widget || w;
const text = typeof src === 'string' ? src : (src.source || src.code || src.text || src.content || '');
if (!text) throw new Error('snake-game source not found in transient');
const patched = text
  .replace(/(requestAnimationFrame\([^)]*\)\s*;?)/g, '$1')
  .replace(/(ctx\.fillRect\(\s*[^;]+?\))/g, '$1')
  .replace(/(draw[A-Za-z]*\s*\([^)]*\)\s*\{[\s\S]*?\n\})/g, '$1');
return await space.current.patchWidget("snake-game", {
  edits: [
    {
      find: /([\s\S]*)/,
      replace: (m) => {
        let s = m;

        if (!/lerp|interpolate|animation|animat/i.test(s)) {
          s = s.replace(
            /let\s+lastUpdate\s*=\s*0\s*;?/,
            `let lastUpdate = 0;
let animFrame = null;
let prevSnake = null;
let nextSnake = null;
let moveProgress = 1;
let moveDuration = 90;`
          );

          s = s.replace(
            /(function\s+step\(\)\s*\{[\s\S]*?)(snake\.unshift\([^\n]*\);\s*\n\s*snake\.pop\(\);\s*)/m,
            `$1prevSnake = snake.map(p => ({ x: p.x, y: p.y }));
snake.unshift({ x: nextX, y: nextY });
snake.pop();
nextSnake = snake.map(p => ({ x: p.x, y: p.y }));
moveProgress = 0;`
          );

          s = s.replace(
            /(function\s+update\(\)\s*\{[\s\S]*?requestAnimationFrame\(update\);\s*\})/m,
            (block) => block.replace(
              /requestAnimationFrame\(update\);/,
              `moveProgress = Math.min(1, moveProgress + (performance.now() - lastUpdate) / moveDuration);
lastUpdate = performance.now();
requestAnimationFrame(update);`
            )
          );

          s = s.replace(
            /(function\s+draw\(\)\s*\{[\s\S]*?)(snake\.forEach\(\(\s*segment,\s*i\s*\)\s*=>\s*\{[\s\S]*?\n\s*\}\s*\);\s*)/m,
            `$1const interp = moveProgress < 1 && prevSnake && nextSnake ? moveProgress : 1;
snake.forEach((segment, i) => {
  const prev = prevSnake && prevSnake[i] ? prevSnake[i] : segment;
  const next = nextSnake && nextSnake[i] ? nextSnake[i] : segment;
  const x = (prev.x + (next.x - prev.x) * interp) * cellSize;
  const y = (prev.y + (next.y - prev.y) * interp) * cellSize;
  const radius = cellSize * 0.42;
  ctx.beginPath();
  ctx.arc(x + cellSize / 2, y + cellSize / 2, radius, 0, Math.PI * 2);
  ctx.fill();
});
`
          );

          s = s.replace(
            /requestAnimationFrame\(draw\);/,
            `lastUpdate = performance.now();
requestAnimationFrame(draw);`
          );
        }

        return s;
      }
    }
  ]
});

