return await space.current.patchWidget("snake-game", {
  edits: [
    {
      type: "replace",
      find: /.*?/s,
      replace: (source) => {
        const styleMatch = source.match(/<style[^>]*>[\s\S]*?<\/style>/i);
        const scriptMatch = source.match(/<script[^>]*>[\s\S]*?<\/script>/i);
        if (!styleMatch || !scriptMatch) return source;

        const style = styleMatch[0].replace(
          /<\/style>/i,
          `
.snake-cell {
  will-change: transform;
  transition: transform 90ms linear;
}
.snake-cell.moving {
  transition-timing-function: cubic-bezier(.2,.8,.2,1);
}
</style>`
        );

        const script = scriptMatch[0].replace(
          /let\s+gridSize\s*=\s*\d+;/,
          `let gridSize = 20;`
        ).replace(
          /function\s+render\(\)\s*\{[\s\S]*?\n\}/,
          (fn) => {
            return fn.replace(
              /cells\.forEach\(\(cell,\s*i\)\s*=>\s*\{[\s\S]*?\n\s*\}\);/s,
              `cells.forEach((cell, i) => {
    const el = document.querySelector(\`[data-cell="\${i}"]\`);
    if (!el) return;
    const prev = cell.prev || cell;
    const dx = (cell.x - prev.x) * gridSize;
    const dy = (cell.y - prev.y) * gridSize;
    el.classList.add('snake-cell');
    el.style.transform = \`translate(\${prev.x * gridSize}px, \${prev.y * gridSize}px)\`;
    requestAnimationFrame(() => {
      el.classList.add('moving');
      el.style.transform = \`translate(\${cell.x * gridSize}px, \${cell.y * gridSize}px)\`;
    });
  });`
            );
          }
        );

        return source.replace(styleMatch[0], style).replace(scriptMatch[0], script);
      }
    }
  ]
})

